import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.concurrent.TimeUnit;
import java.time.Duration;

@SpringBootTest
@Testcontainers
class RedisContainerTest {

    @Container
    @SuppressWarnings("resource")
    static GenericContainer<?> redis = new GenericContainer<>(DockerImageName.parse("redis:7-alpine"))
        .withExposedPorts(6379);

    @DynamicPropertySource
    static void redisProps(DynamicPropertyRegistry r) {
        r.add("spring.data.redis.host", redis::getHost);
        r.add("spring.data.redis.port", ()->redis.getMappedPort(6379).toString());
    }

    @Autowired StringRedisTemplate redisTemplate;

    @Test
    void setAndGet_works() {
        redisTemplate.opsForValue().set("merchant:MRC-001:name", "Flipkart");
        String value = redisTemplate.opsForValue().get("merchant:MRC-001:name");
        assertEquals("Flipkart", value);
    }

    @Test
    void ttl_expiry_works() throws InterruptedException {
        // Set with 1-second TTL:
        redisTemplate.opsForValue().set("rate:MRC-002", "100", Duration.ofSeconds(1));
        assertEquals("100", redisTemplate.opsForValue().get("rate:MRC-002")); // exists

        TimeUnit.SECONDS.sleep(2); // wait for TTL to expire

        String expired = redisTemplate.opsForValue().get("rate:MRC-002");
        assertNull(expired, "Key should have expired after TTL"); // gone!
    }
}

