@SpringBootTest
@Testcontainers
class KafkaContainerTest {

    @Container
    static ConfluentKafkaContainer kafka = new ConfluentKafkaContainer(
        DockerImageName.parse("confluentinc/cp-kafka:7.5.0"));

    @DynamicPropertySource
    static void kafkaProps(DynamicPropertyRegistry r) {
        r.add("spring.kafka.bootstrap-servers", kafka::getBootstrapServers);
        r.add("spring.kafka.consumer.group-id",()->"test-group");
        r.add("spring.kafka.consumer.auto-offset-reset",()->"earliest");
    }

    @Autowired KafkaTemplate<String,String> kafka_template;

    // Simple consumer tracking received messages:
    static CountDownLatch latch = new CountDownLatch(1);
    static String receivedMessage;

    @Component
    static class TestConsumer {
        @KafkaListener(topics="payment.events",groupId="test-group")
        public void consume(String msg) {
            receivedMessage = msg;
            latch.countDown();
        }
    }

    @Test
    void produce_and_consume() throws InterruptedException {
        kafka_template.send("payment.events","PAY-001",
            "{\"paymentId\":\"PAY-001\",\"status\":\"INITIATED\"}");

        // Wait up to 5 seconds for consumer to receive:
        boolean consumed = latch.await(5, TimeUnit.SECONDS);
        assertTrue(consumed, "Message should be consumed within 5 seconds");
        assertTrue(receivedMessage.contains("PAY-001"));
    }
}

