import org.testcontainers.containers.PostgreSQLContainer;
import org.testcontainers.junit.jupiter.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.jdbc.core.JdbcTemplate;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// ABSTRACT BASE: shared container for all tests that extend this
abstract class PostgresIntegrationBase {
    @Container
    static PostgreSQLContainer<?> postgres = new PostgreSQLContainer<>("postgres:15-alpine")
        .withReuse(true); // keep container alive across test runs (local dev)

    @DynamicPropertySource
    static void props(DynamicPropertyRegistry r) {
        r.add("spring.datasource.url",      postgres::getJdbcUrl);
        r.add("spring.datasource.username", postgres::getUsername);
        r.add("spring.datasource.password", postgres::getPassword);
    }
}

// TEST CLASS 1: extends base, gets same container
@SpringBootTest
@Testcontainers
class PaymentTest extends PostgresIntegrationBase {
    @Autowired JdbcTemplate jdbc;

    @BeforeEach
    void clean() {
        // Don't restart container — just clean state!
        try { jdbc.execute("TRUNCATE TABLE payments_test CASCADE"); }
        catch (Exception e) { /* table may not exist yet */ }
    }

    @Test void postgres_running() {
        assertEquals(1, jdbc.queryForObject("SELECT 1", Integer.class));
    }
}

// TEST CLASS 2: also extends base, reuses SAME container instance
@SpringBootTest
@Testcontainers
class OrderTest extends PostgresIntegrationBase {
    @Autowired JdbcTemplate jdbc;

    @Test void postgres_also_running() {
        // Same container as PaymentTest (static field in base class):
        assertEquals(1, jdbc.queryForObject("SELECT 1", Integer.class));
    }
}

// WHY REUSE:
// Without reuse: each @SpringBootTest class starts a NEW container (30-60s each)
// With shared base class: container starts ONCE for all tests that extend it
// Speed gain: 10 test classes × 45s = 450s → 45s (1 container start)
// @BeforeEach truncate: clean slate per test without restarting container

