@SpringBootTest
@Testcontainers
class FullPaymentFlowTest {
    @Container static PostgreSQLContainer<?> postgres=new PostgreSQLContainer<>("postgres:15-alpine");
    @Container @SuppressWarnings("resource")
    static GenericContainer<?> redis=new GenericContainer<>(DockerImageName.parse("redis:7-alpine")).withExposedPorts(6379);

    @DynamicPropertySource
    static void props(DynamicPropertyRegistry r){
        r.add("spring.datasource.url",postgres::getJdbcUrl);
        r.add("spring.datasource.username",postgres::getUsername);
        r.add("spring.datasource.password",postgres::getPassword);
        r.add("spring.data.redis.host",redis::getHost);
        r.add("spring.data.redis.port",()->redis.getMappedPort(6379).toString());
    }

    @Autowired JdbcTemplate jdbc;
    @Autowired StringRedisTemplate redisTemplate;

    @BeforeEach void setup(){
        try{jdbc.execute("CREATE TABLE IF NOT EXISTS rzp_payments (id VARCHAR(50) PRIMARY KEY, merchant_id VARCHAR(50), status VARCHAR(20))");}catch(Exception ignored){}
        redisTemplate.getConnectionFactory().getConnection().flushAll();
    }

    @Test void paymentCachedInRedis(){
        // Create payment in DB:
        jdbc.update("INSERT INTO rzp_payments VALUES (?,?,?)","PAY-001","MRC-001","INITIATED");
        // Cache in Redis:
        redisTemplate.opsForValue().set("payment:PAY-001","INITIATED");
        // Cache hit:
        assertEquals("INITIATED",redisTemplate.opsForValue().get("payment:PAY-001"));
        // DB also has it:
        Map<String,Object> row=jdbc.queryForMap("SELECT * FROM rzp_payments WHERE id=?","PAY-001");
        assertEquals("INITIATED",row.get("status"));
    }

    @Test void cacheInvalidation_onStatusUpdate(){
        jdbc.update("INSERT INTO rzp_payments VALUES (?,?,?)","PAY-002","MRC-001","INITIATED");
        redisTemplate.opsForValue().set("payment:PAY-002","INITIATED");

        // Update status → invalidate cache:
        jdbc.update("UPDATE rzp_payments SET status=? WHERE id=?","COMPLETED","PAY-002");
        redisTemplate.delete("payment:PAY-002"); // cache invalidation

        assertNull(redisTemplate.opsForValue().get("payment:PAY-002")); // cache miss
        Map<String,Object> row=jdbc.queryForMap("SELECT * FROM rzp_payments WHERE id=?","PAY-002");
        assertEquals("COMPLETED",row.get("status")); // DB updated
    }
}

