record PaymentCreatedEvent(String paymentId,String merchantId,long amountPaise){}

@Component
class E2EPaymentConsumer {
    static Map<String,String> processedPayments=new ConcurrentHashMap<>();
    static CountDownLatch latch=new CountDownLatch(1);
    private final ObjectMapper mapper;
    E2EPaymentConsumer(ObjectMapper m){mapper=m;}
    @KafkaListener(topics="payment.created",groupId="e2e-test")
    public void consume(String msg) throws Exception {
        PaymentCreatedEvent ev=mapper.readValue(msg,PaymentCreatedEvent.class);
        processedPayments.put(ev.paymentId(),"RECEIVED");
        latch.countDown();
    }
}

@SpringBootTest @Testcontainers
class KafkaE2ETest {
