        r.add("spring.kafka.consumer.auto-offset-reset",()->"earliest");
        r.add("spring.kafka.consumer.group-id",()->"e2e-test");
    }
    @Autowired KafkaTemplate<String,String> template;
    @Autowired ObjectMapper mapper;

    @Test void fullRoundTrip() throws Exception {
        E2EPaymentConsumer.processedPayments.clear();
        E2EPaymentConsumer.latch=new CountDownLatch(1);

        PaymentCreatedEvent ev=new PaymentCreatedEvent("PAY-E2E-001","MRC-001",500000L);
        template.send("payment.created","PAY-E2E-001",mapper.writeValueAsString(ev));

        boolean consumed=E2EPaymentConsumer.latch.await(10,TimeUnit.SECONDS);
        assertTrue(consumed,"Consumer should have received the event within 10 seconds");
        assertEquals("RECEIVED",E2EPaymentConsumer.processedPayments.get("PAY-E2E-001"));
    }
}

