        redisTemplate.opsForValue().set("pay:"+p.getId(),"PLACED");
        assertEquals("PLACED",redisTemplate.opsForValue().get("pay:"+p.getId()));
    }
    @Test void redis_cacheInvalidation(){
        RzpPayment p=repo.save(new RzpPayment("MRC-D",new BigDecimal("2000.00"),"PLACED"));
        redisTemplate.opsForValue().set("pay:"+p.getId(),"PLACED");
        // Update status → invalidate:
        redisTemplate.delete("pay:"+p.getId());
        assertNull(redisTemplate.opsForValue().get("pay:"+p.getId()));
    }
}

