@SpringBootTest @Testcontainers
class M25T1SynthesisTest {
    @Container static PostgreSQLContainer<?> pg=new PostgreSQLContainer<>("postgres:15-alpine");
    @Container @SuppressWarnings("resource")
    static GenericContainer<?> redis=new GenericContainer<>(DockerImageName.parse("redis:7-alpine")).withExposedPorts(6379);

    @DynamicPropertySource static void props(DynamicPropertyRegistry r){
        r.add("spring.datasource.url",pg::getJdbcUrl);
        r.add("spring.datasource.username",pg::getUsername);
        r.add("spring.datasource.password",pg::getPassword);
        r.add("spring.data.redis.host",redis::getHost);
        r.add("spring.data.redis.port",()->redis.getMappedPort(6379).toString());
    }

    @Autowired SynthPaymentRepo repo;
    @Autowired StringRedisTemplate rt;

    @BeforeEach void clean(){repo.deleteAll();rt.getConnectionFactory().getConnection().flushAll();}

    @Test void db_save(){
