        TimeUnit.SECONDS.sleep(2);
        assertNull(rt.opsForValue().get("synth:ttl"));
    }
    @Test void bothContainers_running(){
        assertTrue(pg.isRunning(),"PostgreSQL container should be running");
        assertTrue(redis.isRunning(),"Redis container should be running");
    }
}
